class Solution:
    def solve(self, input_str) -> bool:
        stack = []
        i = 0
        while i < len(input_str):
            if input_str[i] == '<':
                if input_str[i + 1] == '/':
                    if not stack:
                        return False
                    opening_tag = stack.pop()
                    if input_str[i + 2:i + opening_tag.length + 2] != opening_tag:
                        return False
                    i += opening_tag.length + 2
                else:
                    tag_name = ''
                    j = i + 1
                    while input_str[j] != '>':
                        tag_name += input_str[j]
                        j += 1
                    stack.append(tag_name)
                    i = j
            i += 1
        return stack == []

